+.markdown [data-clearance-diagram-expandable="true"] {
+  position: relative;
+  border-radius: 14px;
+  cursor: zoom-in;
+  transition: background 140ms ease, box-shadow 140ms ease;
+}
+
+.markdown [data-clearance-diagram-expandable="true"]:hover,
+.markdown [data-clearance-diagram-expandable="true"]:focus-visible {
+  background: color-mix(in srgb, var(--surface) 76%, transparent);
+  box-shadow: 0 0 0 1px color-mix(in srgb, var(--link) 22%, transparent);
+  outline: none;
+}
+
+.markdown [data-clearance-diagram-expandable="true"]::after {
+  content: "Expand";
+  position: absolute;
+  top: 10px;
+  right: 10px;
+  padding: 0.35rem 0.6rem;
+  border-radius: 999px;
+  border: 1px solid color-mix(in srgb, var(--surface-border) 88%, transparent);
+  background: color-mix(in srgb, var(--surface) 92%, transparent);
+  color: var(--text);
+  font-family: "SF Pro Text", -apple-system, "Helvetica Neue", sans-serif;
+  font-size: 0.72rem;
+  font-weight: 600;
+  letter-spacing: 0.01em;
+  line-height: 1;
+  opacity: 0;
+  transform: translateY(-2px);
+  transition: opacity 140ms ease, transform 140ms ease;
+  pointer-events: none;
+}
+
+.markdown [data-clearance-diagram-expandable="true"]:hover::after,
+.markdown [data-clearance-diagram-expandable="true"]:focus-visible::after {
+  opacity: 1;
+  transform: translateY(0);
+}
+
 .markdown .graphviz svg {
   display: block;
   max-width: 100%;
   height: auto;
   margin: 0 auto;
 }

+.diagram-overlay {
+  position: fixed;
+  inset: 0;
+  z-index: 999;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  padding: 24px;
+  box-sizing: border-box;
+  background: color-mix(in srgb, var(--bg) 32%, #000 68%);
+  backdrop-filter: blur(12px);
+}
+
+.diagram-overlay-panel {
+  position: relative;
+  width: min(1120px, calc(100vw - 48px));
+  max-height: calc(100vh - 48px);
+  display: flex;
+  flex-direction: column;
+  background: color-mix(in srgb, var(--surface) 94%, var(--bg));
+  border: 1px solid color-mix(in srgb, var(--surface-border) 80%, transparent);
+  border-radius: 20px;
+  box-shadow: 0 28px 80px rgba(0, 0, 0, 0.3);
+  overflow: hidden;
+}
+
+.diagram-overlay-close {
+  position: absolute;
+  top: 16px;
+  right: 16px;
+  border: 1px solid color-mix(in srgb, var(--surface-border) 92%, transparent);
+  border-radius: 999px;
+  background: color-mix(in srgb, var(--surface) 96%, transparent);
+  color: var(--text);
+  padding: 0.45rem 0.8rem;
+  font: inherit;
+  font-size: 0.82rem;
+  font-weight: 600;
+  cursor: pointer;
+}
+
+.diagram-overlay-close:hover,
+.diagram-overlay-close:focus-visible {
+  background: color-mix(in srgb, var(--surface) 82%, var(--link) 18%);
+  outline: none;
+}
+
+.diagram-overlay-body {
+  overflow: auto;
+  padding: 60px 24px 24px;
+}
+
+.diagram-overlay-body svg {
+  display: block;
+  margin: 0 auto;
+  max-width: none;
+  height: auto;
+}
+
+@media (max-width: 720px) {
+  .diagram-overlay {
+    padding: 12px;
+  }
+
+  .diagram-overlay-panel {
+    width: calc(100vw - 24px);
+    max-height: calc(100vh - 24px);
+    border-radius: 16px;
+  }
+
+  .diagram-overlay-close {
+    top: 12px;
+    right: 12px;
+  }
+
+  .diagram-overlay-body {
+    padding: 52px 16px 16px;
+  }
+}
+
 .markdown .math-block {
   margin: 1.1rem 0;
   overflow-x: auto;

